class Solution:
    def findMaxAverage(self, nums, k):
        from itertools import accumulate
        pre = [0]
        for x in nums:
            pre.append(pre[-1] + x)
        best = max(pre[i + k] - pre[i] for i in range(len(nums) - k + 1))
        return best / k

