var findMaxAverage = function(nums, k) {
    let s = 0;
    for (let i = 0; i < k; i++) s += nums[i];
    let best = s;
    for (let i = k; i < nums.length; i++) {
        s += nums[i] - nums[i - k];
        if (s > best) best = s;
    }
    return best / k;
};
